// pubspec: flutter_redux: ^0.10.0, redux: ^5.0.0
import 'package:flutter/material.dart';
import 'package:redux/redux.dart';
import 'package:flutter_redux/flutter_redux.dart';

// 1. State — usually a big class; here just an int for simplicity
typedef AppState = int;

// 2. Actions — plain Dart classes
sealed class CounterAction {}
class Increment extends CounterAction {}
class Decrement extends CounterAction {}
class Reset extends CounterAction {}

// 3. Reducer — pure function: previous state + action -> new state
AppState reducer(AppState state, dynamic action) {
  return switch (action) {
    Increment() => state + 1,
    Decrement() => state - 1,
    Reset() => 0,
    _ => state,
  };
}

void main() {
  final store = Store<AppState>(reducer, initialState: 0);
  runApp(MyApp(store: store));
}

class MyApp extends StatelessWidget {
  const MyApp({super.key, required this.store});
  final Store<AppState> store;

  @override
  Widget build(BuildContext context) => StoreProvider<AppState>(
    store: store,
    child: const MaterialApp(home: HomePage()),
  );
}

class HomePage extends StatelessWidget {
  const HomePage({super.key});

  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('Redux counter')),
    body: Center(
      // Subscribe: rebuild when the projected value changes.
      child: StoreConnector<AppState, int>(
        converter: (store) => store.state,
        builder: (context, count) => Text('$count', style: const TextStyle(fontSize: 40)),
      ),
    ),
    floatingActionButton: StoreConnector<AppState, VoidCallback>(
      converter: (store) => () => store.dispatch(Increment()),
      builder: (context, onPressed) => FloatingActionButton(
        onPressed: onPressed,
        child: const Icon(Icons.add),
      ),
    ),
  );
}

// pubspec: redux_thunk: ^0.4.0
import 'package:redux_thunk/redux_thunk.dart';

// A thunk is a function-shaped action. Instead of dispatching a plain object,
// you dispatch a function that receives the store and can dispatch multiple
// actions over time (loading → data | error).

ThunkAction<AppState> fetchUser(int id) {
  return (Store<AppState> store) async {
    store.dispatch(UserLoading());
    try {
      final user = await api.getUser(id);
      store.dispatch(UserLoaded(user));
    } catch (e) {
      store.dispatch(UserError(e.toString()));
    }
  };
}

// Wire the middleware at store creation:
final store = Store<AppState>(
  reducer,
  initialState: AppState.empty(),
  middleware: [thunkMiddleware],   // enables ThunkAction
);

// From UI:
store.dispatch(fetchUser(42));

